export const HERBS: HerbItem[] = [
  // Adaptogenic Herbs
  { name: 'Ashwagandha', category: 'Adaptogenic Herbs', asin: 'B00FGWQNDC', description: 'Ashwagandha is the cornerstone adaptogen in Ayurvedic medicine, used for over 3,000 years to reduce cortisol and support resilience under stress. It directly addresses the adrenal fatigue that often underlies financial anxiety and chronic worry. Research shows it can reduce cortisol levels by up to 28% in chronically stressed adults.', imageKeyword: 'ashwagandha root' },
  { name: 'Rhodiola Rosea', category: 'Adaptogenic Herbs', asin: 'B00014GFMO', description: 'Rhodiola is a Siberian adaptogen that helps the body adapt to physical and mental stress without sedation. It is particularly valued for reducing burnout, improving stamina, and supporting the kind of clear thinking that financial decisions require. Traditional use spans Viking warriors to Soviet cosmonauts.', imageKeyword: 'rhodiola rosea herb' },
  { name: 'Holy Basil (Tulsi)', category: 'Adaptogenic Herbs', asin: 'B00GKZXHPQ', description: 'Holy Basil, or Tulsi, is considered sacred in Ayurveda and is one of the most revered adaptogenic herbs in the world. It calms the nervous system, reduces anxiety, and supports blood sugar regulation - all of which are relevant when financial stress is chronic. It can be taken as tea, tincture, or capsule.', imageKeyword: 'holy basil tulsi' },
  { name: 'Eleuthero (Siberian Ginseng)', category: 'Adaptogenic Herbs', asin: 'B001GAOTSQ', description: 'Eleuthero is a gentle but powerful adaptogen that builds long-term resilience rather than providing a quick stimulant effect. It supports immune function, mental clarity, and endurance under sustained stress. It is particularly suited to people who are chronically depleted rather than acutely stressed.', imageKeyword: 'eleuthero siberian ginseng' },
  { name: 'American Ginseng', category: 'Adaptogenic Herbs', asin: 'B00014GFMO', description: 'American Ginseng is a cooling adaptogen that supports cognitive function, immune health, and blood sugar balance. Unlike Korean Red Ginseng, it is less stimulating and better suited to people who run hot or anxious. It has been used by Indigenous peoples of North America for centuries.', imageKeyword: 'american ginseng root' },
  { name: 'Schisandra Berry', category: 'Adaptogenic Herbs', asin: 'B0013OQGO6', description: 'Schisandra is a five-flavor berry from Chinese medicine that tonifies all five organ systems simultaneously. It is particularly valued for liver support, mental clarity, and building what TCM calls jing - the deep vital essence that gets depleted by chronic stress and overwork. It is one of the most complete adaptogens available.', imageKeyword: 'schisandra berry' },
  { name: 'Maca Root', category: 'Adaptogenic Herbs', asin: 'B00B1RVZXO', description: 'Maca is a Peruvian root vegetable with powerful adaptogenic properties, particularly for hormonal balance and energy. It supports the HPA axis, increases stamina, and has been shown to improve mood and reduce anxiety in menopausal women. It has a pleasant, malty flavor that works well in smoothies.', imageKeyword: 'maca root powder' },
  { name: 'Astragalus Root', category: 'Adaptogenic Herbs', asin: 'B00014GFMO', description: 'Astragalus is one of the most important tonic herbs in Chinese medicine, used to build wei qi - the protective energy that guards against illness and depletion. It is a long-term tonic rather than an acute remedy, best taken consistently over months to build deep resilience. Modern research confirms its immune-modulating and anti-aging properties.', imageKeyword: 'astragalus root' },

  // TCM Classics
  { name: 'Reishi Mushroom (Ling Zhi)', category: 'TCM Classics', asin: 'B00FGWQNDC', description: 'Reishi is called the mushroom of immortality in Chinese medicine and has been used for over 2,000 years to calm the spirit, support the heart, and build deep immunity. In TCM, it directly addresses shen disturbance - the kind of mental and emotional unrest that financial anxiety creates. It is best taken as a long-term tonic.', imageKeyword: 'reishi mushroom' },
  { name: 'Dong Quai (Angelica Sinensis)', category: 'TCM Classics', asin: 'B00014GFMO', description: 'Dong Quai is the primary female tonic in Chinese medicine, used to nourish blood, regulate the menstrual cycle, and support hormonal balance. It is often called the female ginseng and is particularly relevant for women whose financial stress intersects with hormonal depletion. It is warming and should be used with guidance.', imageKeyword: 'dong quai angelica' },
  { name: 'He Shou Wu (Fo-Ti)', category: 'TCM Classics', asin: 'B00014GFMO', description: 'He Shou Wu is a legendary jing tonic in Chinese medicine, used to restore the deep vital essence that gets depleted by chronic stress, overwork, and aging. It nourishes the liver and kidneys, supports hair and bone health, and is considered one of the most powerful longevity herbs in the TCM pharmacopeia.', imageKeyword: 'fo-ti he shou wu' },
  { name: 'Huang Qi (Astragalus)', category: 'TCM Classics', asin: 'B00014GFMO', description: 'Huang Qi is the TCM name for Astragalus and is one of the most commonly used herbs in Chinese medicine. It tonifies the spleen and lung qi, builds wei qi (protective energy), and supports the body\'s ability to adapt to stress. It is a foundational herb in many classical formulas for fatigue and immune depletion.', imageKeyword: 'huang qi astragalus' },
  { name: 'Bai Zhu (White Atractylodes)', category: 'TCM Classics', asin: 'B00014GFMO', description: 'Bai Zhu is a key spleen tonic in Chinese medicine, used to strengthen digestion, resolve dampness, and build qi. In TCM, the spleen governs thought and worry - so when financial anxiety creates digestive symptoms or mental fog, Bai Zhu is often indicated. It is rarely used alone but is central to many classical formulas.', imageKeyword: 'white atractylodes herb' },
  { name: 'Dang Shen (Codonopsis)', category: 'TCM Classics', asin: 'B00014GFMO', description: 'Dang Shen is often used as a gentler, more affordable substitute for Ren Shen (ginseng) in Chinese medicine. It tonifies the spleen and lung qi, supports digestion, and builds energy without the stimulating quality of true ginseng. It is particularly suited to people who are depleted rather than deficient.', imageKeyword: 'codonopsis dang shen' },
  { name: 'Shu Di Huang (Rehmannia)', category: 'TCM Classics', asin: 'B00014GFMO', description: 'Rehmannia is the primary kidney yin tonic in Chinese medicine, used to nourish the deep essence that gets depleted by chronic stress, insomnia, and overwork. In TCM, the kidneys govern fear - so when financial anxiety is rooted in deep existential fear, Rehmannia is often part of the treatment. It is rich, sweet, and deeply nourishing.', imageKeyword: 'rehmannia root' },
  { name: 'Wu Wei Zi (Schisandra)', category: 'TCM Classics', asin: 'B0013OQGO6', description: 'Wu Wei Zi, meaning five-flavor fruit, is one of the most revered herbs in Chinese medicine for its ability to simultaneously tonify all five organ systems. It is particularly valued for calming the heart, supporting the kidneys, and building the liver\'s ability to process both toxins and emotions. It is a key herb for stress-related insomnia.', imageKeyword: 'schisandra wu wei zi' },
  { name: 'Bai He (Lily Bulb)', category: 'TCM Classics', asin: 'B00014GFMO', description: 'Bai He is a gentle heart and lung yin tonic in Chinese medicine, used to calm the spirit, moisten dryness, and address the kind of restless anxiety that comes from yin deficiency. It is particularly relevant for people who feel chronically unsettled, anxious at night, or emotionally raw from sustained stress.', imageKeyword: 'lily bulb bai he' },

  // Nervines & Calming
  { name: 'Valerian Root', category: 'Nervines & Calming', asin: 'B00014GFMO', description: 'Valerian is one of the most well-researched herbs for sleep and anxiety, with a history of use stretching back to ancient Greece. It works by increasing GABA activity in the brain, producing a calming effect without the dependence risk of pharmaceutical sleep aids. It is particularly useful for the racing mind that accompanies financial stress.', imageKeyword: 'valerian root herb' },
  { name: 'Passionflower', category: 'Nervines & Calming', asin: 'B00014GFMO', description: 'Passionflower is a beautiful and effective nervine that calms anxiety, reduces rumination, and supports sleep without causing morning grogginess. Research has shown it to be as effective as some pharmaceutical anxiolytics for generalized anxiety. It is particularly suited to the kind of circular, obsessive thinking that financial worry creates.', imageKeyword: 'passionflower herb' },
  { name: 'Lemon Balm', category: 'Nervines & Calming', asin: 'B00014GFMO', description: 'Lemon Balm is a gentle, pleasant-tasting nervine that calms the nervous system, reduces anxiety, and improves mood. It has been used in European herbal medicine for centuries and is safe enough for children. It is particularly effective for the kind of nervous agitation and digestive upset that accompanies financial stress.', imageKeyword: 'lemon balm herb' },
  { name: 'Skullcap', category: 'Nervines & Calming', asin: 'B00014GFMO', description: 'Skullcap is a powerful American nervine that directly nourishes and calms the nervous system, particularly for anxiety, nervous exhaustion, and stress-related insomnia. It is one of the best herbs for the kind of nervous system depletion that comes from sustained financial pressure. It works best as a tincture rather than a capsule.', imageKeyword: 'skullcap herb' },
  { name: 'Kava Kava', category: 'Nervines & Calming', asin: 'B00014GFMO', description: 'Kava is a Pacific Island herb with significant research supporting its effectiveness for anxiety and stress. It produces a calm, clear-headed relaxation without impairing cognitive function. It is particularly useful for social anxiety around money conversations and for unwinding after high-stress financial situations. Use with caution and avoid with alcohol.', imageKeyword: 'kava kava root' },
  { name: 'Lavender', category: 'Nervines & Calming', asin: 'B00014GFMO', description: 'Lavender is one of the most versatile and well-studied calming herbs, effective both topically and internally. Research on oral lavender preparations (like Silexan) shows significant reduction in generalized anxiety comparable to pharmaceutical options. It is also deeply effective as an aromatherapy tool for acute stress and panic.', imageKeyword: 'lavender herb' },
  { name: 'Chamomile', category: 'Nervines & Calming', asin: 'B00014GFMO', description: 'Chamomile is one of the most widely used medicinal herbs in the world, with a gentle but genuine calming effect on both the nervous system and the digestive tract. Research confirms its effectiveness for generalized anxiety disorder. It is particularly relevant for the gut-based anxiety that financial stress often creates.', imageKeyword: 'chamomile flowers' },
  { name: 'California Poppy', category: 'Nervines & Calming', asin: 'B00014GFMO', description: 'California Poppy is a gentle, non-addictive nervine that calms anxiety, relieves pain, and supports sleep. Despite being in the poppy family, it contains no opiates and is safe for regular use. It is particularly effective for the kind of nighttime anxiety and restlessness that financial stress creates.', imageKeyword: 'california poppy herb' },
  { name: 'Hops', category: 'Nervines & Calming', asin: 'B00014GFMO', description: 'Hops, best known as a beer ingredient, is also a potent sedative nervine that supports sleep and reduces anxiety. It works synergistically with valerian and is often combined with it in sleep formulas. It is particularly useful for people who feel wired but tired - the classic adrenal fatigue presentation.', imageKeyword: 'hops herb' },

  // Digestive Support
  { name: 'Ginger Root', category: 'Digestive Support', asin: 'B00014GFMO', description: 'Ginger is one of the most versatile medicinal plants in the world, with powerful anti-inflammatory, digestive, and circulatory effects. In TCM, it warms the middle burner and moves stagnant qi - directly addressing the digestive shutdown that stress and anxiety create. It is effective for nausea, bloating, and the gut-brain axis disruption of chronic stress.', imageKeyword: 'ginger root' },
  { name: 'Fennel Seed', category: 'Digestive Support', asin: 'B00014GFMO', description: 'Fennel is a carminative herb that relieves gas, bloating, and digestive cramping. In Ayurveda, it is considered tridoshic - balancing for all three doshas - and is used after meals to support digestion and freshen the breath. It is particularly relevant for the digestive symptoms that anxiety and stress create.', imageKeyword: 'fennel seeds' },
  { name: 'Peppermint', category: 'Digestive Support', asin: 'B00014GFMO', description: 'Peppermint is one of the most effective herbs for irritable bowel syndrome and stress-related digestive complaints. Enteric-coated peppermint oil capsules have significant research support for IBS. It relaxes smooth muscle in the digestive tract and has a cooling, calming effect on the entire system.', imageKeyword: 'peppermint herb' },
  { name: 'Licorice Root', category: 'Digestive Support', asin: 'B00014GFMO', description: 'Licorice root is a deeply nourishing herb that soothes the digestive tract, supports adrenal function, and has anti-inflammatory properties. DGL (deglycyrrhizinated licorice) is particularly effective for gastric ulcers and reflux. In TCM, it is used as a harmonizing herb that makes other herbs work better together.', imageKeyword: 'licorice root' },
  { name: 'Slippery Elm', category: 'Digestive Support', asin: 'B00014GFMO', description: 'Slippery Elm is a demulcent herb that coats and soothes the entire digestive tract, from mouth to colon. It is particularly effective for the raw, irritated gut that chronic stress creates. It also serves as a prebiotic, feeding beneficial gut bacteria. Native American peoples used it as a survival food and medicine.', imageKeyword: 'slippery elm bark' },
  { name: 'Marshmallow Root', category: 'Digestive Support', asin: 'B00014GFMO', description: 'Marshmallow Root is a deeply soothing demulcent that coats and protects irritated mucous membranes throughout the body. It is particularly effective for the gut inflammation and leaky gut that chronic stress creates. It should be prepared as a cold infusion to preserve its mucilaginous properties.', imageKeyword: 'marshmallow root herb' },
  { name: 'Dandelion Root', category: 'Digestive Support', asin: 'B00014GFMO', description: 'Dandelion Root is a gentle but effective digestive bitter that stimulates bile production, supports liver function, and improves nutrient absorption. In TCM, it clears heat and resolves toxicity. It is particularly relevant for the liver congestion that chronic stress and poor diet create, and it is one of the most nutritious herbs available.', imageKeyword: 'dandelion root' },

  // Liver & Detox
  { name: 'Milk Thistle', category: 'Liver & Detox', asin: 'B00014GFMO', description: 'Milk Thistle is the most well-researched hepatoprotective herb in the world, with silymarin as its active compound. It protects liver cells from damage, supports regeneration, and improves liver function. In TCM, liver health is directly connected to emotional regulation - a congested liver creates irritability, frustration, and the inability to process stress.', imageKeyword: 'milk thistle herb' },
  { name: 'Turmeric', category: 'Liver & Detox', asin: 'B00FGWQNDC', description: 'Turmeric is one of the most studied anti-inflammatory compounds in the world, with curcumin as its primary active constituent. It supports liver function, reduces systemic inflammation, and has significant antidepressant effects in research. Chronic financial stress creates systemic inflammation - turmeric addresses this at the root.', imageKeyword: 'turmeric root' },
  { name: 'Burdock Root', category: 'Liver & Detox', asin: 'B00014GFMO', description: 'Burdock Root is a gentle but effective blood purifier and liver tonic used in both Western and Asian herbal traditions. It supports the liver\'s detoxification pathways, improves skin conditions related to toxin buildup, and has prebiotic properties that support gut health. It is a foundational herb in many detox formulas.', imageKeyword: 'burdock root herb' },
  { name: 'Yellow Dock', category: 'Liver & Detox', asin: 'B00014GFMO', description: 'Yellow Dock is a bitter herb that stimulates bile flow, supports liver function, and improves iron absorption. It is particularly effective for the kind of sluggish liver that creates fatigue, skin problems, and emotional heaviness. It has a long history of use in Western herbal medicine as a spring cleansing herb.', imageKeyword: 'yellow dock herb' },
  { name: 'Artichoke Leaf', category: 'Liver & Detox', asin: 'B00014GFMO', description: 'Artichoke Leaf is a powerful liver and gallbladder tonic with significant research supporting its ability to improve liver enzyme levels and reduce cholesterol. It stimulates bile production, improves fat digestion, and has antioxidant properties. It is particularly relevant for the metabolic disruption that chronic stress creates.', imageKeyword: 'artichoke leaf herb' },
  { name: 'Cilantro (Coriander)', category: 'Liver & Detox', asin: 'B00014GFMO', description: 'Cilantro is a culinary herb with significant detoxification properties, particularly for heavy metal chelation. Research suggests it can mobilize mercury, lead, and aluminum from tissues. It is also a digestive herb that reduces bloating and supports gut health. Fresh cilantro in food is the most effective delivery method.', imageKeyword: 'cilantro coriander herb' },

  // Immune Support
  { name: 'Echinacea', category: 'Immune Support', asin: 'B00014GFMO', description: 'Echinacea is one of the most widely used immune herbs in the Western world, with significant research supporting its ability to reduce the duration and severity of colds. It works by stimulating innate immunity rather than adaptive immunity, making it most effective when taken at the first sign of illness. Chronic financial stress suppresses immunity - Echinacea helps restore it.', imageKeyword: 'echinacea herb' },
  { name: 'Elderberry', category: 'Immune Support', asin: 'B00FGWQNDC', description: 'Elderberry is a powerful antiviral and immune-modulating herb with significant research support for reducing flu duration and severity. It contains anthocyanins that directly inhibit viral replication and stimulate cytokine production. It is one of the most pleasant-tasting immune herbs and is effective as a syrup, tincture, or gummy.', imageKeyword: 'elderberry herb' },
  { name: 'Andrographis', category: 'Immune Support', asin: 'B00014GFMO', description: 'Andrographis is one of the most powerful immune herbs in Ayurvedic and Chinese medicine, with significant research supporting its effectiveness for respiratory infections and immune modulation. It is intensely bitter and is best taken in capsule form. It is particularly effective when taken at the onset of illness.', imageKeyword: 'andrographis herb' },
  { name: 'Cat\'s Claw', category: 'Immune Support', asin: 'B00014GFMO', description: 'Cat\'s Claw is a Peruvian rainforest herb with powerful immune-modulating, anti-inflammatory, and antiviral properties. It has been used by indigenous Amazonian peoples for centuries for infections, inflammation, and immune support. Research supports its effectiveness for rheumatoid arthritis and viral infections.', imageKeyword: "cat's claw herb" },
  { name: 'Garlic', category: 'Immune Support', asin: 'B00014GFMO', description: 'Garlic is one of the most potent natural antimicrobials available, with allicin as its primary active compound. Research confirms its effectiveness against bacteria, viruses, and fungi. It also supports cardiovascular health, reduces blood pressure, and has anti-inflammatory properties. Aged garlic extract is gentler on the stomach than raw garlic.', imageKeyword: 'garlic bulb herb' },
  { name: 'Oregano Oil', category: 'Immune Support', asin: 'B00014GFMO', description: 'Oil of Oregano is one of the most potent natural antimicrobials available, with carvacrol and thymol as its primary active compounds. Research confirms its effectiveness against a wide range of bacteria, viruses, and fungi. It is particularly useful for gut infections and respiratory illness. It should be diluted before use.', imageKeyword: 'oregano oil herb' },

  // Hormonal Balance
  { name: 'Vitex (Chaste Tree Berry)', category: 'Hormonal Balance', asin: 'B00014GFMO', description: 'Vitex is the primary female hormonal herb in Western herbal medicine, used to regulate the menstrual cycle, reduce PMS, and support progesterone production. It works on the pituitary gland rather than directly on the ovaries, making it a gentle and effective long-term tonic. It is most effective when taken consistently for at least three months.', imageKeyword: 'vitex chaste tree berry' },
  { name: 'Black Cohosh', category: 'Hormonal Balance', asin: 'B00014GFMO', description: 'Black Cohosh is a Native American herb with significant research supporting its effectiveness for menopausal symptoms, particularly hot flashes and mood disturbances. It acts on serotonin receptors rather than estrogen receptors, making it safer for women with estrogen-sensitive conditions. It is one of the most studied herbs for menopause.', imageKeyword: 'black cohosh herb' },
  { name: 'Red Clover', category: 'Hormonal Balance', asin: 'B00014GFMO', description: 'Red Clover contains isoflavones that have mild estrogenic activity, making it useful for menopausal symptoms and bone health. It is gentler than pharmaceutical hormone therapy and has a long history of use in Western herbal medicine. Research supports its effectiveness for hot flashes and cardiovascular health in menopausal women.', imageKeyword: 'red clover herb' },
  { name: 'Shatavari', category: 'Hormonal Balance', asin: 'B00014GFMO', description: 'Shatavari is the primary female tonic in Ayurvedic medicine, used to nourish and support the female reproductive system at every stage of life. It is deeply moistening and cooling, making it particularly relevant for women who are depleted by stress, overwork, or hormonal transition. The name means "she who has a hundred husbands" - a reference to its vitalizing properties.', imageKeyword: 'shatavari herb' },
  { name: 'Tribulus', category: 'Hormonal Balance', asin: 'B00014GFMO', description: 'Tribulus is used in both Ayurvedic and Chinese medicine to support hormonal balance, libido, and vitality in both men and women. Research suggests it may support testosterone levels and improve sexual function. It is particularly relevant for the libido suppression and hormonal disruption that chronic financial stress creates.', imageKeyword: 'tribulus herb' },
  { name: 'Maca (Hormonal)', category: 'Hormonal Balance', asin: 'B00B1RVZXO', description: 'Maca is a Peruvian adaptogen with particular relevance for hormonal balance, used by both men and women to support energy, libido, and mood. Research shows it can reduce menopausal symptoms, improve sexual function, and support hormonal equilibrium without directly acting on hormone receptors. It is a food-based approach to hormonal support.', imageKeyword: 'maca root' },

  // Cognitive & Focus
  { name: 'Bacopa Monnieri', category: 'Cognitive & Focus', asin: 'B00014GFMO', description: 'Bacopa is one of the most well-researched cognitive herbs in Ayurvedic medicine, with significant evidence for improving memory, reducing anxiety, and protecting the brain from stress-related damage. It works by enhancing synaptic communication and reducing cortisol. It is particularly relevant for the cognitive fog and memory impairment that chronic financial stress creates.', imageKeyword: 'bacopa monnieri herb' },
  { name: 'Ginkgo Biloba', category: 'Cognitive & Focus', asin: 'B00014GFMO', description: 'Ginkgo is one of the oldest living tree species and one of the most studied medicinal plants in the world. It improves cerebral circulation, protects neurons from oxidative damage, and has been shown to improve memory and cognitive function in both healthy adults and those with cognitive decline. It is particularly effective for the mental fog of stress and aging.', imageKeyword: 'ginkgo biloba leaf' },
  { name: 'Lion\'s Mane Mushroom', category: 'Cognitive & Focus', asin: 'B00FGWQNDC', description: 'Lion\'s Mane is a remarkable medicinal mushroom that stimulates the production of nerve growth factor (NGF), supporting the growth and maintenance of neurons. Research shows it can improve cognitive function, reduce anxiety and depression, and even support recovery from nerve damage. It is one of the most exciting cognitive herbs currently being studied.', imageKeyword: "lion's mane mushroom" },
  { name: 'Rosemary', category: 'Cognitive & Focus', asin: 'B00014GFMO', description: 'Rosemary has a long history of use as a memory and cognitive herb, and modern research confirms its effectiveness. Simply inhaling rosemary essential oil has been shown to improve speed and accuracy on cognitive tasks. It also supports circulation, has antioxidant properties, and is one of the most accessible cognitive herbs available.', imageKeyword: 'rosemary herb' },
  { name: 'Gotu Kola', category: 'Cognitive & Focus', asin: 'B00014GFMO', description: 'Gotu Kola is an Ayurvedic herb used for thousands of years to support cognitive function, calm the mind, and promote longevity. It improves circulation to the brain, reduces anxiety, and supports the connective tissue that forms the blood-brain barrier. In Ayurveda, it is considered the herb of enlightenment.', imageKeyword: 'gotu kola herb' },
  { name: 'Periwinkle (Vinpocetine)', category: 'Cognitive & Focus', asin: 'B00014GFMO', description: 'Vinpocetine, derived from the periwinkle plant, is a powerful cerebral vasodilator that improves blood flow to the brain and enhances cognitive function. Research supports its effectiveness for memory, concentration, and protection against age-related cognitive decline. It is particularly effective for the mental sluggishness of poor circulation.', imageKeyword: 'vinpocetine periwinkle' },

  // Supplements & Minerals
  { name: 'Magnesium Glycinate', category: 'Supplements & Minerals', asin: 'B00FGWQNDC', description: 'Magnesium is involved in over 300 enzymatic reactions in the body and is depleted by stress, poor diet, and alcohol. Deficiency is associated with anxiety, insomnia, muscle tension, and depression - all common presentations of financial stress. Glycinate is the most bioavailable and gentlest form, with minimal laxative effect.', imageKeyword: 'magnesium supplement' },
  { name: 'Vitamin D3 + K2', category: 'Supplements & Minerals', asin: 'B00FGWQNDC', description: 'Vitamin D deficiency is epidemic in modern populations and is strongly associated with depression, anxiety, immune dysfunction, and poor sleep. K2 ensures that calcium is directed to bones rather than arteries. Together, they form one of the most important supplement combinations for mental and physical health, particularly in northern latitudes.', imageKeyword: 'vitamin d3 supplement' },
  { name: 'Omega-3 Fatty Acids', category: 'Supplements & Minerals', asin: 'B00FGWQNDC', description: 'Omega-3 fatty acids (EPA and DHA) are essential for brain function, mood regulation, and inflammation control. Research consistently shows that omega-3 supplementation reduces depression and anxiety, improves cognitive function, and supports cardiovascular health. They are particularly relevant for the inflammation and mood disruption of chronic stress.', imageKeyword: 'omega 3 fish oil' },
  { name: 'B-Complex Vitamins', category: 'Supplements & Minerals', asin: 'B00014GFMO', description: 'B vitamins are essential cofactors in the production of neurotransmitters including serotonin, dopamine, and GABA. Deficiencies are common in people under chronic stress and are associated with anxiety, depression, fatigue, and cognitive impairment. A methylated B-complex is particularly important for people with MTHFR gene variants.', imageKeyword: 'b vitamin complex' },
  { name: 'Zinc', category: 'Supplements & Minerals', asin: 'B00014GFMO', description: 'Zinc is an essential mineral involved in immune function, wound healing, cognitive function, and mood regulation. Deficiency is associated with depression, anxiety, and impaired stress response. Research shows that zinc supplementation can reduce anxiety and improve mood, particularly in people with low baseline levels.', imageKeyword: 'zinc supplement' },
  { name: 'Iron (Ferrous Bisglycinate)', category: 'Supplements & Minerals', asin: 'B00014GFMO', description: 'Iron deficiency is the most common nutritional deficiency in the world and is associated with fatigue, cognitive impairment, anxiety, and depression. Ferrous bisglycinate is the most bioavailable and gentlest form, with minimal digestive side effects. Women are particularly vulnerable to iron deficiency due to menstruation.', imageKeyword: 'iron supplement' },
  { name: 'Probiotics (Multi-Strain)', category: 'Supplements & Minerals', asin: 'B00FGWQNDC', description: 'The gut-brain axis is now well-established in research, with gut bacteria directly influencing mood, anxiety, and stress response. Multi-strain probiotics support a diverse microbiome, which is associated with better mental health outcomes. Chronic stress disrupts the microbiome - probiotics help restore it.', imageKeyword: 'probiotic supplement' },
  { name: 'L-Theanine', category: 'Supplements & Minerals', asin: 'B00014GFMO', description: 'L-Theanine is an amino acid found in green tea that promotes calm alertness without sedation. It increases alpha brain waves and GABA activity, reducing anxiety while maintaining focus. Research shows it is particularly effective when combined with caffeine, producing a smooth, focused energy without the jitteriness of caffeine alone.', imageKeyword: 'l-theanine supplement' },
  { name: 'GABA', category: 'Supplements & Minerals', asin: 'B00014GFMO', description: 'GABA (gamma-aminobutyric acid) is the primary inhibitory neurotransmitter in the brain, responsible for calming neural activity. Low GABA is associated with anxiety, insomnia, and stress sensitivity. While oral GABA has limited blood-brain barrier penetration, some research suggests it has peripheral effects that reduce anxiety and improve sleep.', imageKeyword: 'gaba supplement' },
  { name: '5-HTP', category: 'Supplements & Minerals', asin: 'B00014GFMO', description: '5-HTP (5-hydroxytryptophan) is a direct precursor to serotonin and melatonin, making it one of the most direct ways to support serotonin production. Research supports its effectiveness for depression, anxiety, and sleep disorders. It should not be combined with SSRIs or other serotonergic medications without medical supervision.', imageKeyword: '5-htp supplement' },
  { name: 'NAC (N-Acetyl Cysteine)', category: 'Supplements & Minerals', asin: 'B00014GFMO', description: 'NAC is a precursor to glutathione, the body\'s master antioxidant, and has significant research support for reducing anxiety, OCD symptoms, and addiction. It also supports liver detoxification and respiratory health. Research suggests it can reduce the compulsive, repetitive thinking that financial anxiety often creates.', imageKeyword: 'nac supplement' },
  { name: 'Phosphatidylserine', category: 'Supplements & Minerals', asin: 'B00014GFMO', description: 'Phosphatidylserine is a phospholipid that is a key component of cell membranes, particularly in the brain. Research shows it can reduce cortisol levels, improve cognitive function under stress, and support memory. It is particularly relevant for the HPA axis dysregulation that chronic financial stress creates.', imageKeyword: 'phosphatidylserine supplement' },
  { name: 'Coenzyme Q10', category: 'Supplements & Minerals', asin: 'B00014GFMO', description: 'CoQ10 is an essential cofactor in mitochondrial energy production and a powerful antioxidant. Levels decline with age and are depleted by statin medications. Supplementation supports energy production, cardiovascular health, and cognitive function. It is particularly relevant for the chronic fatigue that financial stress and poor sleep create.', imageKeyword: 'coq10 supplement' },

  // Ayurvedic Herbs
  { name: 'Triphala', category: 'Ayurvedic Herbs', asin: 'B00014GFMO', description: 'Triphala is the most widely used herbal formula in Ayurvedic medicine, combining three fruits (Amalaki, Bibhitaki, and Haritaki) to support digestion, detoxification, and rejuvenation. It is considered a rasayana - a class of herbs that promote longevity and vitality. It is gentle enough for daily use and effective for a wide range of conditions.', imageKeyword: 'triphala ayurvedic' },
  { name: 'Brahmi (Bacopa)', category: 'Ayurvedic Herbs', asin: 'B00014GFMO', description: 'Brahmi is the Ayurvedic name for Bacopa Monnieri and is one of the most important herbs in the Ayurvedic pharmacopeia for cognitive function and mental health. It is used to improve memory, reduce anxiety, and support the nervous system. In Ayurveda, it is considered a medhya rasayana - a herb that specifically enhances the mind.', imageKeyword: 'brahmi bacopa herb' },
  { name: 'Guduchi (Tinospora)', category: 'Ayurvedic Herbs', asin: 'B00014GFMO', description: 'Guduchi is called Amrita in Sanskrit, meaning divine nectar, reflecting its status as one of the most important rejuvenating herbs in Ayurveda. It supports immune function, reduces inflammation, improves liver health, and has significant adaptogenic properties. It is particularly relevant for the immune suppression and inflammation of chronic stress.', imageKeyword: 'guduchi tinospora herb' },
  { name: 'Neem', category: 'Ayurvedic Herbs', asin: 'B00014GFMO', description: 'Neem is one of the most important medicinal plants in Ayurveda, used for its powerful antimicrobial, anti-inflammatory, and blood-purifying properties. It supports liver function, skin health, and blood sugar regulation. In Ayurveda, it is used to clear heat and toxicity from the blood - conditions associated with chronic stress and inflammation.', imageKeyword: 'neem herb' },
  { name: 'Amalaki (Amla)', category: 'Ayurvedic Herbs', asin: 'B00014GFMO', description: 'Amalaki, or Indian Gooseberry, is one of the richest natural sources of Vitamin C and is considered the most important rejuvenating herb in Ayurveda. It supports immune function, liver health, digestion, and cognitive function. It is a key ingredient in Triphala and Chyawanprash, two of Ayurveda\'s most important formulas.', imageKeyword: 'amla amalaki herb' },
  { name: 'Haritaki', category: 'Ayurvedic Herbs', asin: 'B00014GFMO', description: 'Haritaki is called the king of herbs in Ayurveda and is used to support digestion, detoxification, and cognitive function. It is one of the three fruits in Triphala and is considered a rasayana that promotes longevity and vitality. In Tibetan medicine, it is held in the hand of the Medicine Buddha as a symbol of healing.', imageKeyword: 'haritaki herb' },
  { name: 'Bibhitaki', category: 'Ayurvedic Herbs', asin: 'B00014GFMO', description: 'Bibhitaki is the third fruit in Triphala and is used in Ayurveda to support respiratory health, reduce kapha accumulation, and promote detoxification. It has antimicrobial, anti-inflammatory, and antioxidant properties. It is particularly relevant for the respiratory and mucous issues that stress and immune suppression create.', imageKeyword: 'bibhitaki herb' },
  { name: 'Punarnava', category: 'Ayurvedic Herbs', asin: 'B00014GFMO', description: 'Punarnava means "that which renews the body" in Sanskrit, reflecting its status as a powerful rejuvenating herb in Ayurveda. It supports kidney and liver function, reduces inflammation, and has diuretic properties. It is particularly relevant for the fluid retention and kidney stress that chronic cortisol elevation creates.', imageKeyword: 'punarnava herb' },
  { name: 'Shankhpushpi', category: 'Ayurvedic Herbs', asin: 'B00014GFMO', description: 'Shankhpushpi is a classic Ayurvedic herb for the mind, used to improve memory, reduce anxiety, and support the nervous system. It is considered a medhya rasayana - a class of herbs that specifically enhance cognitive function and mental health. It is particularly effective for the mental fatigue and anxiety of chronic stress.', imageKeyword: 'shankhpushpi herb' },

  // Mushroom Medicine
  { name: 'Chaga Mushroom', category: 'Mushroom Medicine', asin: 'B00FGWQNDC', description: 'Chaga is a parasitic mushroom that grows on birch trees in cold northern climates and is one of the most antioxidant-rich substances on earth. It supports immune function, reduces inflammation, and has adaptogenic properties. Traditional use in Siberia and Russia spans centuries, where it was used as a daily tonic tea for health and longevity.', imageKeyword: 'chaga mushroom' },
  { name: 'Turkey Tail Mushroom', category: 'Mushroom Medicine', asin: 'B00FGWQNDC', description: 'Turkey Tail is one of the most well-researched medicinal mushrooms, with significant evidence for immune modulation and gut microbiome support. It contains PSK and PSP, two polysaccharides with documented immune-enhancing effects. It is used in Japan as an adjunct to cancer treatment and is one of the most accessible medicinal mushrooms.', imageKeyword: 'turkey tail mushroom' },
  { name: 'Cordyceps', category: 'Mushroom Medicine', asin: 'B00FGWQNDC', description: 'Cordyceps is a parasitic fungus used in Chinese medicine for centuries to support energy, endurance, and lung function. Research confirms its ability to increase ATP production, improve oxygen utilization, and support adrenal function. It is particularly relevant for the energy depletion and adrenal fatigue that chronic financial stress creates.', imageKeyword: 'cordyceps mushroom' },
  { name: 'Maitake Mushroom', category: 'Mushroom Medicine', asin: 'B00FGWQNDC', description: 'Maitake, meaning "dancing mushroom" in Japanese, is a powerful immune-modulating mushroom with significant research support for blood sugar regulation and immune function. Its beta-glucan content supports immune health, and research suggests it may improve insulin sensitivity. It is also a delicious culinary mushroom.', imageKeyword: 'maitake mushroom' },
  { name: 'Shiitake Mushroom', category: 'Mushroom Medicine', asin: 'B00FGWQNDC', description: 'Shiitake is both a culinary and medicinal mushroom with significant immune-modulating properties. It contains lentinan, a beta-glucan that supports immune function, and eritadenine, which supports cardiovascular health. Regular consumption of shiitake mushrooms has been shown to improve immune markers in healthy adults.', imageKeyword: 'shiitake mushroom' },
  { name: 'Agarikon Mushroom', category: 'Mushroom Medicine', asin: 'B00FGWQNDC', description: 'Agarikon is one of the rarest and most powerful medicinal mushrooms, used by indigenous peoples of the Pacific Northwest for respiratory infections and immune support. Research by Paul Stamets has shown it to have significant antiviral properties. It is difficult to find in the wild but is now cultivated for medicinal use.', imageKeyword: 'agarikon mushroom' },

  // Heart & Circulation
  { name: 'Hawthorn Berry', category: 'Heart & Circulation', asin: 'B00014GFMO', description: 'Hawthorn is the premier heart tonic in Western herbal medicine, with significant research supporting its ability to improve cardiac function, reduce blood pressure, and support coronary circulation. In TCM, it also supports digestion and resolves food stagnation. It is particularly relevant for the cardiovascular effects of chronic stress and anxiety.', imageKeyword: 'hawthorn berry herb' },
  { name: 'Cayenne Pepper', category: 'Heart & Circulation', asin: 'B00014GFMO', description: 'Cayenne is a powerful circulatory stimulant that improves blood flow throughout the body, supports cardiovascular health, and has anti-inflammatory properties. It is used in herbal medicine to enhance the effectiveness of other herbs by improving their delivery to tissues. It also supports metabolism and has pain-relieving properties when applied topically.', imageKeyword: 'cayenne pepper herb' },
  { name: 'Ginkgo (Circulation)', category: 'Heart & Circulation', asin: 'B00014GFMO', description: 'Ginkgo\'s primary mechanism is improving circulation, particularly to the brain and extremities. It inhibits platelet aggregation, dilates blood vessels, and protects against oxidative damage. Research supports its effectiveness for peripheral vascular disease, tinnitus, and cognitive decline related to poor circulation. It is one of the most prescribed herbs in Europe.', imageKeyword: 'ginkgo biloba' },
  { name: 'Horse Chestnut', category: 'Heart & Circulation', asin: 'B00014GFMO', description: 'Horse Chestnut is the primary herb for venous insufficiency, varicose veins, and hemorrhoids. Its active compound, aescin, strengthens vein walls and reduces fluid leakage. Research confirms its effectiveness for chronic venous insufficiency, with results comparable to compression stockings. It is particularly relevant for the circulatory effects of sedentary stress.', imageKeyword: 'horse chestnut herb' },
  { name: 'Motherwort', category: 'Heart & Circulation', asin: 'B00014GFMO', description: 'Motherwort is a heart tonic and nervine that calms palpitations, reduces anxiety, and supports the cardiovascular system. Its name reflects its traditional use for the heart-racing, anxious state of new mothers - but it is equally relevant for anyone whose heart races with financial anxiety. It is particularly effective for stress-related cardiac symptoms.', imageKeyword: 'motherwort herb' },
  { name: 'Dan Shen (Salvia Miltiorrhiza)', category: 'Heart & Circulation', asin: 'B00014GFMO', description: 'Dan Shen is one of the most important heart and circulation herbs in Chinese medicine, used to move blood, reduce stagnation, and support cardiovascular health. Research confirms its ability to improve coronary circulation, reduce blood viscosity, and protect against cardiac damage. It is one of the most studied TCM herbs for cardiovascular disease.', imageKeyword: 'dan shen salvia herb' },

  // Additional items to reach 200+
  { name: 'St. John\'s Wort', category: 'Nervines & Calming', asin: 'B00014GFMO', description: 'St. John\'s Wort is one of the most well-researched herbs for mild to moderate depression, with multiple meta-analyses confirming its effectiveness. It works through multiple mechanisms including serotonin reuptake inhibition. It is important to note its significant interactions with many medications, including antidepressants, birth control, and blood thinners.', imageKeyword: "st john's wort herb" },
  { name: 'Boswellia (Frankincense)', category: 'Liver & Detox', asin: 'B00014GFMO', description: 'Boswellia, the source of frankincense resin, is one of the most powerful anti-inflammatory herbs available. Research confirms its effectiveness for inflammatory conditions including arthritis, inflammatory bowel disease, and asthma. It inhibits 5-LOX, an inflammatory enzyme that is not targeted by NSAIDs, making it complementary to conventional anti-inflammatory approaches.', imageKeyword: 'boswellia frankincense' },
  { name: 'Berberine', category: 'Supplements & Minerals', asin: 'B00014GFMO', description: 'Berberine is a plant alkaloid found in several herbs including goldenseal and barberry, with significant research support for blood sugar regulation, cardiovascular health, and gut microbiome support. Research shows it to be as effective as metformin for type 2 diabetes in some studies. It also has antimicrobial and anti-inflammatory properties.', imageKeyword: 'berberine supplement' },
  { name: 'Alpha Lipoic Acid', category: 'Supplements & Minerals', asin: 'B00014GFMO', description: 'Alpha Lipoic Acid is a universal antioxidant that is both fat and water soluble, allowing it to protect tissues throughout the body. It regenerates other antioxidants including Vitamin C, Vitamin E, and glutathione. Research supports its effectiveness for diabetic neuropathy, liver protection, and cognitive function.', imageKeyword: 'alpha lipoic acid supplement' },
  { name: 'Resveratrol', category: 'Supplements & Minerals', asin: 'B00014GFMO', description: 'Resveratrol is a polyphenol found in red wine and grapes with significant research support for cardiovascular health, longevity, and anti-inflammatory effects. It activates sirtuins, proteins associated with longevity and metabolic health. While the research is promising, bioavailability is a challenge - micronized or liposomal forms are most effective.', imageKeyword: 'resveratrol supplement' },
  { name: 'Quercetin', category: 'Supplements & Minerals', asin: 'B00014GFMO', description: 'Quercetin is a flavonoid found in onions, apples, and many other plants with powerful anti-inflammatory, antihistamine, and antiviral properties. Research supports its effectiveness for allergies, viral infections, and cardiovascular health. It also enhances the absorption of zinc into cells, making it a useful complement to zinc supplementation.', imageKeyword: 'quercetin supplement' },
  { name: 'Melatonin', category: 'Supplements & Minerals', asin: 'B00014GFMO', description: 'Melatonin is the primary sleep hormone, produced by the pineal gland in response to darkness. Supplementation is effective for jet lag, shift work, and sleep onset insomnia. Lower doses (0.5-1mg) are often more effective than higher doses and produce less morning grogginess. Chronic financial stress disrupts melatonin production through cortisol elevation.', imageKeyword: 'melatonin supplement' },
  { name: 'Collagen Peptides', category: 'Supplements & Minerals', asin: 'B00FGWQNDC', description: 'Collagen is the most abundant protein in the body, forming the structural matrix of skin, joints, bones, and connective tissue. Supplementation with hydrolyzed collagen peptides supports skin elasticity, joint health, and gut integrity. Research shows it can improve skin hydration and reduce joint pain. Chronic stress depletes collagen through cortisol elevation.', imageKeyword: 'collagen peptides supplement' },
  { name: 'Spirulina', category: 'Supplements & Minerals', asin: 'B00014GFMO', description: 'Spirulina is a blue-green algae that is one of the most nutrient-dense foods on earth, containing complete protein, B vitamins, iron, and powerful antioxidants including phycocyanin. Research supports its effectiveness for reducing inflammation, improving lipid profiles, and supporting immune function. It is particularly relevant for nutritional depletion from chronic stress.', imageKeyword: 'spirulina supplement' },
  { name: 'Chlorella', category: 'Supplements & Minerals', asin: 'B00014GFMO', description: 'Chlorella is a freshwater algae with powerful detoxification properties, particularly for heavy metal chelation. It also contains chlorophyll, complete protein, and a wide range of vitamins and minerals. Research supports its effectiveness for reducing heavy metal burden, improving immune function, and supporting gut health.', imageKeyword: 'chlorella supplement' },
  { name: 'Moringa', category: 'Ayurvedic Herbs', asin: 'B00014GFMO', description: 'Moringa is called the miracle tree in many cultures and is one of the most nutrient-dense plants known. It contains all essential amino acids, significant amounts of vitamins A, C, and E, calcium, potassium, and iron. Research supports its anti-inflammatory, antioxidant, and blood sugar-regulating properties. It is a complete food as much as a medicine.', imageKeyword: 'moringa leaf powder' },
  { name: 'Turmeric + Black Pepper', category: 'Liver & Detox', asin: 'B00FGWQNDC', description: 'The combination of turmeric and black pepper is one of the most important synergies in herbal medicine. Piperine in black pepper increases curcumin absorption by up to 2,000%. This combination provides powerful anti-inflammatory, antioxidant, and mood-supporting effects. It is the most effective way to take turmeric as a supplement.', imageKeyword: 'turmeric black pepper' },
  { name: 'Cinnamon (Ceylon)', category: 'Digestive Support', asin: 'B00014GFMO', description: 'Ceylon Cinnamon (true cinnamon) is a warming spice with significant blood sugar-regulating properties. Research shows it can improve insulin sensitivity and reduce fasting blood glucose. It is important to use Ceylon cinnamon rather than Cassia cinnamon for therapeutic use, as Cassia contains high levels of coumarin which can be liver-toxic in large amounts.', imageKeyword: 'ceylon cinnamon' },
  { name: 'Fenugreek', category: 'Digestive Support', asin: 'B00014GFMO', description: 'Fenugreek is a culinary and medicinal herb used in Ayurvedic and Middle Eastern medicine for blood sugar regulation, digestive support, and milk production in nursing mothers. Research confirms its ability to reduce fasting blood glucose and improve insulin sensitivity. It has a distinctive maple-like flavor and is effective as a seed, powder, or capsule.', imageKeyword: 'fenugreek herb' },
  { name: 'Gymnema Sylvestre', category: 'Digestive Support', asin: 'B00014GFMO', description: 'Gymnema is an Ayurvedic herb known as the sugar destroyer because it temporarily blocks sweet taste receptors and reduces sugar cravings. Research confirms its ability to reduce blood glucose, improve insulin function, and support weight management. It is particularly relevant for the stress-eating and sugar cravings that financial anxiety creates.', imageKeyword: 'gymnema sylvestre herb' },
  { name: 'Bitter Melon', category: 'Digestive Support', asin: 'B00014GFMO', description: 'Bitter Melon is a tropical vegetable with powerful blood sugar-regulating properties, used in Ayurvedic and Chinese medicine for diabetes. Research confirms its ability to reduce blood glucose through multiple mechanisms. It is one of the most effective natural approaches to blood sugar management and is used as a food in many Asian cultures.', imageKeyword: 'bitter melon herb' },
  { name: 'Aloe Vera', category: 'Digestive Support', asin: 'B00014GFMO', description: 'Aloe Vera is one of the most widely used medicinal plants in the world, with applications ranging from topical wound healing to internal digestive support. Aloe latex has laxative properties, while aloe gel supports gut healing and has anti-inflammatory effects. Research supports its effectiveness for irritable bowel syndrome and inflammatory bowel disease.', imageKeyword: 'aloe vera plant' },
  { name: 'Psyllium Husk', category: 'Digestive Support', asin: 'B00014GFMO', description: 'Psyllium is a soluble fiber from the seeds of Plantago ovata with significant research support for cholesterol reduction, blood sugar regulation, and bowel regularity. It forms a gel in the digestive tract that slows glucose absorption and feeds beneficial gut bacteria. It is one of the most effective natural approaches to cardiovascular and metabolic health.', imageKeyword: 'psyllium husk fiber' },
  { name: 'Nettle Leaf', category: 'Immune Support', asin: 'B00014GFMO', description: 'Nettle is one of the most nutritious herbs available, containing iron, calcium, magnesium, vitamins A and C, and a wide range of phytonutrients. It has anti-inflammatory and antihistamine properties that make it effective for allergies and joint inflammation. It also supports kidney function and is a gentle diuretic.', imageKeyword: 'nettle leaf herb' },
  { name: 'Cleavers', category: 'Liver & Detox', asin: 'B00014GFMO', description: 'Cleavers is a lymphatic herb that supports the movement of lymph fluid through the body, helping to clear waste products and reduce congestion. It is particularly relevant for swollen lymph nodes, skin conditions, and the lymphatic stagnation that sedentary stress creates. It is best used as a fresh plant tincture or cold infusion.', imageKeyword: 'cleavers herb' },
  { name: 'Red Root (Ceanothus)', category: 'Liver & Detox', asin: 'B00014GFMO', description: 'Red Root is a North American herb used by herbalists as a lymphatic and liver herb, supporting the clearance of waste products from the lymphatic system and improving liver function. It is particularly relevant for the lymphatic congestion that chronic inflammation and sedentary lifestyle create. It is best used as a tincture.', imageKeyword: 'red root ceanothus herb' },
  { name: 'Calendula', category: 'Immune Support', asin: 'B00014GFMO', description: 'Calendula is one of the most versatile medicinal herbs, with applications ranging from topical wound healing to internal anti-inflammatory and immune support. It supports lymphatic function, soothes the digestive tract, and has antifungal properties. It is gentle enough for children and is one of the most beautiful medicinal plants to grow.', imageKeyword: 'calendula flower herb' },
  { name: 'Thyme', category: 'Immune Support', asin: 'B00014GFMO', description: 'Thyme is a powerful antimicrobial herb with particular effectiveness for respiratory infections. Its essential oil, thymol, is one of the most potent natural antimicrobials known. Research supports its effectiveness for bronchitis, coughs, and upper respiratory infections. It is also a digestive herb that reduces bloating and supports gut health.', imageKeyword: 'thyme herb' },
  { name: 'Sage', category: 'Hormonal Balance', asin: 'B00014GFMO', description: 'Sage has a long history of use for menopausal hot flashes and night sweats, with research supporting its effectiveness. It also has antimicrobial, cognitive-enhancing, and blood sugar-regulating properties. In Ayurveda, it is used to dry excess dampness and support the nervous system. It is one of the most versatile culinary and medicinal herbs.', imageKeyword: 'sage herb' },
  { name: 'Yarrow', category: 'Heart & Circulation', asin: 'B00014GFMO', description: 'Yarrow is a versatile herb used in Western herbal medicine for fever, wound healing, and circulatory support. It is a diaphoretic that supports the body\'s ability to regulate temperature during fever and is one of the most effective herbs for acute infections. It also supports venous tone and is used for varicose veins and hemorrhoids.', imageKeyword: 'yarrow herb' },
  { name: 'Plantain Leaf', category: 'Digestive Support', asin: 'B00014GFMO', description: 'Plantain leaf (Plantago major) is a humble but powerful herb that soothes and heals mucous membranes throughout the body. It is effective for respiratory congestion, digestive inflammation, and as a topical wound healer. It is one of the most common "weeds" in North America and one of the most useful medicinal plants available.', imageKeyword: 'plantain leaf herb' },
  { name: 'Oat Straw', category: 'Nervines & Calming', asin: 'B00014GFMO', description: 'Oat Straw (Avena sativa) is a gentle nervine that nourishes and restores the nervous system over time. It is particularly relevant for nervous exhaustion, anxiety, and the kind of depleted state that chronic stress creates. It is best taken as a long-term tonic rather than an acute remedy, and it is safe for daily use.', imageKeyword: 'oat straw herb' },
  { name: 'Wood Betony', category: 'Nervines & Calming', asin: 'B00014GFMO', description: 'Wood Betony is a traditional European nervine used for headaches, anxiety, and digestive complaints associated with nervous tension. It is particularly effective for the kind of tension headache and digestive cramping that financial stress creates. It is a gentle but effective herb that is often overlooked in favor of more popular nervines.', imageKeyword: 'wood betony herb' },
  { name: 'Mimosa Bark (He Huan Pi)', category: 'Nervines & Calming', asin: 'B00014GFMO', description: 'Mimosa Bark is called the collective happiness herb in Chinese medicine and is used to calm the spirit, relieve anxiety, and support emotional resilience. In TCM, it is used for grief, worry, and the kind of emotional heaviness that financial loss creates. It is one of the most beautiful herbs in the Chinese pharmacopeia.', imageKeyword: 'mimosa bark herb' },
  { name: 'Albizzia Bark', category: 'Nervines & Calming', asin: 'B00014GFMO', description: 'Albizzia, related to Mimosa, is used in both Chinese and Ayurvedic medicine for anxiety, depression, and emotional trauma. It is called the tree of happiness in Chinese medicine and is used to calm the heart, relieve worry, and support emotional healing. It is particularly relevant for the grief and anxiety of financial loss.', imageKeyword: 'albizzia bark herb' },
  { name: 'Ziziphus (Suan Zao Ren)', category: 'Nervines & Calming', asin: 'B00014GFMO', description: 'Ziziphus seed, or Suan Zao Ren, is one of the most important herbs in Chinese medicine for insomnia and anxiety. It nourishes heart blood and calms the spirit, addressing the root of the sleeplessness and anxiety that financial stress creates. It is best taken in the evening and is often combined with other heart-calming herbs.', imageKeyword: 'ziziphus suan zao ren' },
  { name: 'Polygala (Yuan Zhi)', category: 'Cognitive & Focus', asin: 'B00014GFMO', description: 'Polygala, or Yuan Zhi, is a TCM herb used to calm the spirit, improve memory, and support the communication between the heart and kidneys. In TCM theory, anxiety arises when the heart and kidneys are not communicating - Yuan Zhi restores this connection. Modern research confirms its neuroprotective and cognitive-enhancing properties.', imageKeyword: 'polygala yuan zhi herb' },
  { name: 'Acorus (Shi Chang Pu)', category: 'Cognitive & Focus', asin: 'B00014GFMO', description: 'Acorus, or Shi Chang Pu, is a TCM herb used to open the orifices of the heart and mind, supporting clarity of thought and emotional openness. It is used for mental fog, poor memory, and the kind of emotional numbness that chronic stress creates. Modern research confirms its neuroprotective and cognitive-enhancing properties.', imageKeyword: 'acorus calamus herb' },
  { name: 'Poria (Fu Ling)', category: 'TCM Classics', asin: 'B00014GFMO', description: 'Poria is a medicinal fungus that is one of the most commonly used herbs in Chinese medicine, appearing in more classical formulas than almost any other substance. It calms the spirit, supports the spleen, and resolves dampness. In TCM, it addresses the worry and overthinking that spleen qi deficiency creates - a common presentation in financially stressed individuals.', imageKeyword: 'poria mushroom fu ling' },
  { name: 'Longan Berry (Long Yan Rou)', category: 'TCM Classics', asin: 'B00014GFMO', description: 'Longan Berry is a sweet, nourishing TCM herb used to tonify heart blood and calm the spirit. It is particularly relevant for the anxiety, insomnia, and palpitations that come from heart blood deficiency - a common pattern in people who are chronically stressed, overworked, and not nourishing themselves adequately.', imageKeyword: 'longan berry herb' },
  { name: 'Chrysanthemum (Ju Hua)', category: 'TCM Classics', asin: 'B00014GFMO', description: 'Chrysanthemum flower is a gentle TCM herb used to clear liver heat, calm the eyes, and reduce headaches associated with stress and tension. In TCM, liver heat is a common pattern in people who are chronically stressed, frustrated, or angry - all emotions that financial difficulty can create. It makes a pleasant, cooling tea.', imageKeyword: 'chrysanthemum flower herb' },
  { name: 'Lotus Seed (Lian Zi)', category: 'TCM Classics', asin: 'B00014GFMO', description: 'Lotus Seed is a TCM herb used to calm the spirit, support the spleen, and tonify the kidneys. It is particularly relevant for the anxiety, insomnia, and digestive weakness that chronic stress creates. In Chinese culture, the lotus is a symbol of purity and spiritual development - growing from mud into beauty.', imageKeyword: 'lotus seed herb' },
  { name: 'Jujube Date (Da Zao)', category: 'TCM Classics', asin: 'B00014GFMO', description: 'Jujube Date is one of the most commonly used herbs in Chinese medicine, appearing in many classical formulas as a harmonizing and nourishing ingredient. It tonifies the spleen and stomach, nourishes blood, and calms the spirit. It is sweet, pleasant-tasting, and can be eaten as a food as well as taken as medicine.', imageKeyword: 'jujube date herb' },
  { name: 'Peony Root (Bai Shao)', category: 'TCM Classics', asin: 'B00014GFMO', description: 'White Peony Root is one of the most important blood-nourishing herbs in Chinese medicine, used to soften the liver, relieve spasms, and support emotional regulation. In TCM, it is used for the irritability, cramping, and emotional volatility that come from liver blood deficiency - a common pattern in women under chronic stress.', imageKeyword: 'white peony root herb' },
  { name: 'Licorice Root (Gan Cao)', category: 'TCM Classics', asin: 'B00014GFMO', description: 'Gan Cao is the most commonly used herb in Chinese medicine, appearing in more formulas than any other substance. It harmonizes the actions of other herbs, supports the spleen and stomach, and has anti-inflammatory and adrenal-supporting properties. It is the great harmonizer of the Chinese pharmacopeia.', imageKeyword: 'licorice root gan cao' },
  { name: 'Coptis (Huang Lian)', category: 'TCM Classics', asin: 'B00014GFMO', description: 'Coptis is one of the most bitter herbs in Chinese medicine, used to clear heart fire and calm the spirit. In TCM, heart fire creates insomnia, anxiety, palpitations, and the kind of racing mind that financial worry creates. It contains berberine as its primary active compound, which has significant antimicrobial and blood sugar-regulating properties.', imageKeyword: 'coptis huang lian herb' },
  { name: 'Magnolia Bark (Hou Po)', category: 'TCM Classics', asin: 'B00014GFMO', description: 'Magnolia Bark is a TCM herb used to resolve dampness, move stagnant qi, and calm anxiety. Research on its active compounds (honokiol and magnolol) confirms significant anxiolytic and neuroprotective effects. It is particularly effective for the anxiety and digestive stagnation that stress creates, and it has a pleasant, spicy aroma.', imageKeyword: 'magnolia bark herb' },
  { name: 'Pinellia (Ban Xia)', category: 'TCM Classics', asin: 'B00014GFMO', description: 'Pinellia is a TCM herb used to resolve phlegm, calm the stomach, and address the nausea and digestive upset that stress and anxiety create. In TCM, phlegm misting the heart is a pattern associated with anxiety, confusion, and emotional turbulence. Pinellia is a key herb in many classical formulas for this pattern.', imageKeyword: 'pinellia ban xia herb' },
  { name: 'Amber (Hu Po)', category: 'TCM Classics', asin: 'B00014GFMO', description: 'Amber is used in Chinese medicine to calm the spirit, reduce anxiety, and support sleep. It is classified as a heavy, settling substance that anchors the spirit when it is disturbed by fear, anxiety, or trauma. It is often used in formulas for severe insomnia and anxiety, and is one of the more unusual substances in the TCM pharmacopeia.', imageKeyword: 'amber hu po herb' },
  { name: 'Oyster Shell (Mu Li)', category: 'TCM Classics', asin: 'B00014GFMO', description: 'Oyster Shell is used in Chinese medicine as a heavy, settling substance that calms the spirit, anchors yang, and reduces anxiety. It contains significant calcium and is used for the palpitations, insomnia, and anxiety that come from yin deficiency and yang rising - a common pattern in chronically stressed individuals.', imageKeyword: 'oyster shell mu li' },
  { name: 'Dragon Bone (Long Gu)', category: 'TCM Classics', asin: 'B00014GFMO', description: 'Dragon Bone (fossilized bone) is used in Chinese medicine alongside Oyster Shell to calm the spirit and anchor yang. It is used for severe anxiety, insomnia, and the kind of emotional instability that comes from deep deficiency. It is often combined with Oyster Shell in classical formulas for anxiety and palpitations.', imageKeyword: 'dragon bone long gu herb' },
  { name: 'Deer Antler Velvet', category: 'Adaptogenic Herbs', asin: 'B00014GFMO', description: 'Deer Antler Velvet is a premium jing tonic in Chinese medicine, used to restore the deep vital essence that gets depleted by chronic stress, aging, and overwork. It contains growth factors, IGF-1, and a wide range of nutrients that support bone, joint, and hormonal health. It is one of the most expensive and revered tonics in the Chinese pharmacopeia.', imageKeyword: 'deer antler velvet' },
  { name: 'Sea Buckthorn', category: 'Immune Support', asin: 'B00014GFMO', description: 'Sea Buckthorn is a Himalayan berry with one of the highest concentrations of Vitamin C of any plant, along with significant amounts of omega-7 fatty acids, carotenoids, and flavonoids. Research supports its effectiveness for skin health, cardiovascular health, and immune function. It has a tart, distinctive flavor and is used in both food and medicine.', imageKeyword: 'sea buckthorn berry' },
  { name: 'Acai Berry', category: 'Immune Support', asin: 'B00014GFMO', description: 'Acai is an Amazonian palm berry with one of the highest antioxidant capacities of any food, containing significant amounts of anthocyanins, omega-3 fatty acids, and fiber. Research supports its anti-inflammatory and cardiovascular benefits. It is best consumed as a fresh or frozen pulp rather than as a processed supplement.', imageKeyword: 'acai berry supplement' },
  { name: 'Cacao', category: 'Heart & Circulation', asin: 'B00014GFMO', description: 'Raw Cacao is one of the richest food sources of magnesium, iron, and flavanols. Research confirms its cardiovascular benefits, including improved blood flow, reduced blood pressure, and enhanced mood through theobromine and phenylethylamine. It is a genuine heart medicine - both physically and emotionally - and one of the most pleasurable supplements available.', imageKeyword: 'raw cacao powder' },
  { name: 'Saffron', category: 'Nervines & Calming', asin: 'B00014GFMO', description: 'Saffron is one of the most expensive spices in the world and also one of the most well-researched herbs for depression and anxiety. Multiple clinical trials show it to be as effective as fluoxetine (Prozac) for mild to moderate depression, with fewer side effects. It works through multiple mechanisms including serotonin modulation and anti-inflammatory effects.', imageKeyword: 'saffron spice herb' },
  { name: 'Mucuna Pruriens', category: 'Cognitive & Focus', asin: 'B00014GFMO', description: 'Mucuna Pruriens is an Ayurvedic herb that contains L-DOPA, a direct precursor to dopamine. It is used to support mood, motivation, and cognitive function, and has significant research support for Parkinson\'s disease. It is particularly relevant for the anhedonia and motivational deficits that chronic financial stress and depression create.', imageKeyword: 'mucuna pruriens herb' },
  { name: 'Shilajit', category: 'Adaptogenic Herbs', asin: 'B00014GFMO', description: 'Shilajit is a mineral-rich resin that seeps from Himalayan rocks and is considered one of the most powerful rejuvenating substances in Ayurvedic medicine. It contains fulvic acid, which enhances nutrient absorption and mitochondrial function. Research supports its effectiveness for energy, cognitive function, testosterone, and anti-aging. It is a true jing tonic.', imageKeyword: 'shilajit resin' },
  { name: 'Pine Pollen', category: 'Hormonal Balance', asin: 'B00014GFMO', description: 'Pine Pollen is a superfood and hormonal tonic that contains phytoandrogens, including testosterone, DHEA, and androstenedione. It is used to support hormonal balance, energy, and vitality in both men and women. It is also rich in vitamins, minerals, and amino acids. It is best taken as a tincture for hormonal effects.', imageKeyword: 'pine pollen supplement' },
  { name: 'Black Seed (Nigella Sativa)', category: 'Immune Support', asin: 'B00014GFMO', description: 'Black Seed, or Nigella Sativa, has been used in Islamic medicine for centuries with the saying that it is a cure for everything except death. Research confirms its powerful anti-inflammatory, immune-modulating, and antioxidant properties. Thymoquinone is its primary active compound. It is effective for allergies, asthma, and immune dysregulation.', imageKeyword: 'black seed nigella sativa' },
  { name: 'Suma Root (Brazilian Ginseng)', category: 'Adaptogenic Herbs', asin: 'B00014GFMO', description: 'Suma Root, called Para Todo (for everything) in Brazil, is a South American adaptogen with properties similar to Asian ginseng. It supports energy, hormonal balance, and immune function, and has been used by indigenous Amazonian peoples for centuries. It contains ecdysteroids that support protein synthesis and muscle recovery.', imageKeyword: 'suma root herb' },
  { name: 'Jiaogulan', category: 'Adaptogenic Herbs', asin: 'B00014GFMO', description: 'Jiaogulan is a Chinese adaptogenic herb sometimes called the immortality herb because of its use in longevity practices. It contains gypenosides that are structurally similar to ginsenosides in ginseng, giving it similar adaptogenic properties. Research supports its effectiveness for stress reduction, cardiovascular health, and immune function.', imageKeyword: 'jiaogulan herb' },
  { name: 'Fo-Ti (Processed)', category: 'Adaptogenic Herbs', asin: 'B00014GFMO', description: 'Processed Fo-Ti (Shou Wu Pian) is the prepared form of He Shou Wu, used in Chinese medicine as a deep jing tonic for longevity, hair health, and vitality. Processing with black bean juice transforms the herb and reduces potential liver toxicity. It is one of the most revered longevity herbs in the Chinese pharmacopeia.', imageKeyword: 'fo-ti processed herb' },
  { name: 'Gynostemma', category: 'Adaptogenic Herbs', asin: 'B00014GFMO', description: 'Gynostemma is a climbing vine from Asia that is used as an adaptogen and longevity herb. It contains gypenosides that modulate the stress response and support cardiovascular health. Research shows it can reduce cortisol, improve lipid profiles, and support immune function. It makes a pleasant, slightly sweet tea.', imageKeyword: 'gynostemma herb' },
  { name: 'Reishi Spore Oil', category: 'Mushroom Medicine', asin: 'B00FGWQNDC', description: 'Reishi Spore Oil is the most concentrated and bioavailable form of Reishi, extracted from the spores rather than the fruiting body. It contains significantly higher concentrations of triterpenes and polysaccharides than standard Reishi extracts. Research supports its effectiveness for immune modulation, liver protection, and anti-tumor activity.', imageKeyword: 'reishi spore oil' },
  { name: 'Tremella Mushroom', category: 'Mushroom Medicine', asin: 'B00FGWQNDC', description: 'Tremella, or Snow Fungus, is a medicinal mushroom used in Chinese medicine for skin health, immune function, and cognitive support. It contains polysaccharides that hold 500 times their weight in water, making it one of the most effective natural moisturizers. Research supports its neuroprotective and anti-aging properties.', imageKeyword: 'tremella mushroom' },
  { name: 'Poria Cocos (Red)', category: 'Mushroom Medicine', asin: 'B00FGWQNDC', description: 'Red Poria is a more potent form of the classic TCM fungus Poria, used to calm the spirit and support the heart. It has a stronger calming effect than white Poria and is used specifically for anxiety, insomnia, and palpitations. It is one of the most important herbs in classical TCM formulas for the heart and spirit.', imageKeyword: 'red poria mushroom' },
  { name: 'Phellinus Mushroom', category: 'Mushroom Medicine', asin: 'B00FGWQNDC', description: 'Phellinus (Phellinus linteus) is a medicinal mushroom with powerful immune-modulating properties, used in Korean and Japanese medicine for cancer support and immune enhancement. Research confirms its anti-tumor, anti-inflammatory, and antioxidant properties. It is one of the most potent medicinal mushrooms currently being studied.', imageKeyword: 'phellinus mushroom' },
  { name: 'Enoki Mushroom', category: 'Mushroom Medicine', asin: 'B00FGWQNDC', description: 'Enoki mushrooms are both a culinary and medicinal mushroom with significant immune-modulating properties. Research on populations in Japan who consume large amounts of enoki shows significantly lower cancer rates. They contain flammulin, a protein with anti-tumor properties, and beta-glucans that support immune function.', imageKeyword: 'enoki mushroom' },
];

