export const HERBS_EXTRA: HerbItem[] = [
  { name: 'Elderflower', category: 'Immune Support', asin: 'B00014GFMO', description: 'Elderflower is the blossom of the elder tree, used in European herbal medicine for fever, colds, and sinus congestion. It is a gentle diaphoretic that supports the body\'s ability to process fever and clear mucous. It makes a beautiful, fragrant tea and is one of the most pleasant-tasting medicinal herbs available.', imageKeyword: 'elderflower herb' },
  { name: 'Meadowsweet', category: 'Digestive Support', asin: 'B00014GFMO', description: 'Meadowsweet contains salicylates, the natural compounds that inspired the development of aspirin. It soothes the digestive tract, reduces inflammation, and relieves pain without the gastric irritation of aspirin. It is particularly effective for the gastric ulcers and reflux that chronic stress creates.', imageKeyword: 'meadowsweet herb' },
  { name: 'Cramp Bark', category: 'Hormonal Balance', asin: 'B00014GFMO', description: 'Cramp Bark is a North American herb used for uterine cramping, muscle spasms, and tension. It is one of the most effective herbs for menstrual cramps and is also useful for the muscle tension and spasm that chronic stress creates throughout the body. It works by relaxing smooth muscle throughout the body.', imageKeyword: 'cramp bark herb' },
  { name: 'Wild Yam', category: 'Hormonal Balance', asin: 'B00014GFMO', description: 'Wild Yam contains diosgenin, a plant steroid that is the raw material for synthesizing progesterone in the laboratory. While the body cannot convert diosgenin to progesterone directly, Wild Yam has anti-spasmodic and anti-inflammatory properties that support the female reproductive system. It is used for menstrual cramps and menopausal symptoms.', imageKeyword: 'wild yam herb' },
  { name: 'Shepherd\'s Purse', category: 'Heart & Circulation', asin: 'B00014GFMO', description: 'Shepherd\'s Purse is a common garden weed with powerful hemostatic properties, used to reduce heavy menstrual bleeding and support vascular tone. It is one of the most effective herbs for the heavy periods that hormonal imbalance and stress create. It is also used for urinary tract infections and as a general tonic.', imageKeyword: "shepherd's purse herb" },
  { name: 'Agrimony', category: 'Digestive Support', asin: 'B00014GFMO', description: 'Agrimony is a gentle astringent herb used in European herbal medicine for digestive complaints, liver support, and urinary tract health. It is particularly effective for the diarrhea and digestive irritability that anxiety creates. In flower essence therapy, it is used for people who hide their troubles behind a cheerful facade.', imageKeyword: 'agrimony herb' },
  { name: 'Vervain', category: 'Nervines & Calming', asin: 'B00014GFMO', description: 'Vervain is a nervine and liver herb used in European herbal medicine for nervous exhaustion, tension headaches, and liver congestion. In flower essence therapy, it is the remedy for the over-enthusiastic perfectionist who drives themselves to exhaustion - a profile that often accompanies financial overwork and burnout.', imageKeyword: 'vervain herb' },
  { name: 'Betony', category: 'Nervines & Calming', asin: 'B00014GFMO', description: 'Betony (Stachys betonica) is an ancient European herb used for headaches, anxiety, and digestive complaints associated with nervous tension. It was considered a panacea in medieval European medicine and is still used by herbalists for the kind of tension headache and digestive cramping that financial stress creates.', imageKeyword: 'betony herb' },
  { name: 'Motherwort (Leonurus)', category: 'Heart & Circulation', asin: 'B00014GFMO', description: 'Motherwort is a heart tonic and uterine herb that calms palpitations, reduces anxiety, and supports the cardiovascular system. Its Latin name, Leonurus cardiaca, means lion-hearted, reflecting its use for courage and heart strength. It is particularly effective for the anxiety and palpitations that financial fear creates.', imageKeyword: 'motherwort leonurus herb' },
  { name: 'Linden Flower', category: 'Nervines & Calming', asin: 'B00014GFMO', description: 'Linden Flower (Tilia) is a gentle nervine and diaphoretic used in European herbal medicine for anxiety, insomnia, and fever. It makes a beautiful, fragrant tea that calms the nervous system and supports cardiovascular health. It is particularly effective for the kind of nervous tension and mild hypertension that financial stress creates.', imageKeyword: 'linden flower herb' },
  { name: 'Catnip', category: 'Nervines & Calming', asin: 'B00014GFMO', description: 'Catnip is a gentle nervine and carminative that calms anxiety, reduces digestive cramping, and supports sleep. Despite its stimulating effect on cats, it has a calming effect on humans. It is particularly effective for the nervous digestive complaints and insomnia that anxiety creates, and is safe for children.', imageKeyword: 'catnip herb' },
  { name: 'Blue Vervain', category: 'Nervines & Calming', asin: 'B00014GFMO', description: 'Blue Vervain is a North American nervine used for the kind of rigid, tense, over-controlled state that chronic stress creates. It is particularly relevant for people who hold tension in the neck and shoulders, clench their jaw, and find it difficult to let go and relax. It is one of the most specific nervines for the stress of perfectionism.', imageKeyword: 'blue vervain herb' },
  { name: 'Milky Oats', category: 'Nervines & Calming', asin: 'B00014GFMO', description: 'Milky Oats (Avena sativa, harvested in the milky stage) is one of the most nourishing nervines available, used to restore a depleted nervous system over time. It is particularly relevant for the kind of nervous exhaustion, burnout, and emotional depletion that sustained financial stress creates. It is best taken as a fresh plant tincture.', imageKeyword: 'milky oats herb' },
  { name: 'Ashwagandha KSM-66', category: 'Adaptogenic Herbs', asin: 'B00FGWQNDC', description: 'KSM-66 is a patented, full-spectrum ashwagandha root extract with the highest concentration and purity of any ashwagandha extract currently available. Multiple clinical trials confirm its effectiveness for reducing cortisol, improving sleep, enhancing cognitive function, and supporting thyroid health. It is the gold standard form of ashwagandha for therapeutic use.', imageKeyword: 'ashwagandha ksm-66' },
  { name: 'Rhodiola Rosea (3% Rosavins)', category: 'Adaptogenic Herbs', asin: 'B00014GFMO', description: 'Standardized Rhodiola extract with 3% rosavins and 1% salidroside is the form used in most clinical research. This standardization ensures consistent potency and effectiveness. Research confirms its ability to reduce cortisol, improve cognitive performance under stress, and reduce burnout. It is one of the most evidence-based adaptogens available.', imageKeyword: 'rhodiola rosea extract' },
  { name: 'Panax Ginseng (Korean Red)', category: 'Adaptogenic Herbs', asin: 'B00014GFMO', description: 'Korean Red Ginseng is the most studied and revered form of ginseng, prepared by steaming and drying the root to increase its potency. Research confirms its effectiveness for energy, cognitive function, immune support, and sexual health. It is a warming, stimulating adaptogen best suited to people who are cold, depleted, and low-energy.', imageKeyword: 'korean red ginseng' },
  { name: 'Shatavari (Asparagus Racemosus)', category: 'Ayurvedic Herbs', asin: 'B00014GFMO', description: 'Shatavari is the primary female tonic in Ayurvedic medicine, used to nourish and support the female reproductive system at every stage of life. Research confirms its effectiveness for menopausal symptoms, milk production in nursing mothers, and hormonal balance. It is deeply moistening and cooling, making it ideal for women who are depleted by stress.', imageKeyword: 'shatavari asparagus racemosus' },
  { name: 'Vidari Kanda', category: 'Ayurvedic Herbs', asin: 'B00014GFMO', description: 'Vidari Kanda is an Ayurvedic rejuvenating herb used to build ojas - the vital essence that underlies immunity, vitality, and mental clarity. It is deeply nourishing and is used for depletion, weakness, and the kind of deep fatigue that chronic stress creates. It is particularly relevant for people who have been running on empty for too long.', imageKeyword: 'vidari kanda herb' },
  { name: 'Kapikacchu (Mucuna)', category: 'Ayurvedic Herbs', asin: 'B00014GFMO', description: 'Kapikacchu is the Ayurvedic name for Mucuna Pruriens and is used as a powerful rejuvenating herb for the nervous system and reproductive system. In Ayurveda, it is considered a vajikarana herb - one that supports sexual vitality and reproductive health. Its L-DOPA content makes it particularly relevant for mood and motivation support.', imageKeyword: 'kapikacchu mucuna herb' },
  { name: 'Pippali (Long Pepper)', category: 'Ayurvedic Herbs', asin: 'B00014GFMO', description: 'Pippali is a warming spice used in Ayurveda to enhance the bioavailability of other herbs, support digestion, and clear respiratory congestion. It is one of the three ingredients in Trikatu, a classical Ayurvedic formula for digestive fire. Like black pepper, it contains piperine, which enhances the absorption of many nutrients and herbs.', imageKeyword: 'pippali long pepper' },
  { name: 'Vidanga', category: 'Digestive Support', asin: 'B00014GFMO', description: 'Vidanga is an Ayurvedic herb used primarily as an antiparasitic and digestive herb. It is one of the most effective natural approaches to intestinal parasites and is also used for skin conditions and respiratory complaints. In Ayurveda, it is used to clear ama (undigested toxins) from the digestive tract.', imageKeyword: 'vidanga herb' },
  { name: 'Kutki (Picrorhiza)', category: 'Liver & Detox', asin: 'B00014GFMO', description: 'Kutki is one of the most important liver herbs in Ayurvedic medicine, used to clear liver heat, reduce inflammation, and support liver regeneration. Research confirms its hepatoprotective properties, comparable to milk thistle. It is particularly relevant for the liver congestion and inflammation that chronic stress and poor diet create.', imageKeyword: 'kutki picrorhiza herb' },
  { name: 'Andrographis Paniculata', category: 'Immune Support', asin: 'B00014GFMO', description: 'Andrographis is one of the most bitter and powerful immune herbs in Ayurvedic and Chinese medicine. Multiple clinical trials confirm its effectiveness for reducing the duration and severity of upper respiratory infections. It has significant anti-inflammatory properties and is used for a wide range of infectious and inflammatory conditions.', imageKeyword: 'andrographis paniculata herb' },
  { name: 'Bhringraj', category: 'Ayurvedic Herbs', asin: 'B00014GFMO', description: 'Bhringraj is an Ayurvedic herb used primarily for liver support, hair health, and as a rasayana (rejuvenating tonic). It is called the king of hair herbs in Ayurveda and is used both internally and as a scalp oil. Research confirms its hepatoprotective properties and its effectiveness for promoting hair growth.', imageKeyword: 'bhringraj herb' },
  { name: 'Manjistha', category: 'Liver & Detox', asin: 'B00014GFMO', description: 'Manjistha is the primary blood-purifying herb in Ayurvedic medicine, used to clear heat and toxins from the blood, support lymphatic function, and improve skin health. It is particularly relevant for the skin conditions, inflammation, and lymphatic congestion that chronic stress and poor diet create. It has a beautiful red color and is used as a natural dye.', imageKeyword: 'manjistha herb' },
  { name: 'Noni', category: 'Immune Support', asin: 'B00014GFMO', description: 'Noni (Morinda citrifolia) is a Polynesian fruit used traditionally for pain, immune support, and general health. Research supports its anti-inflammatory, antioxidant, and immune-modulating properties. It contains proxeronine, which may support cellular function. It has a distinctive, pungent flavor that is an acquired taste.', imageKeyword: 'noni fruit herb' },
  { name: 'Graviola (Soursop)', category: 'Immune Support', asin: 'B00014GFMO', description: 'Graviola is a tropical fruit tree with significant research on its acetogenins, compounds with potent anti-tumor and antimicrobial properties. It is used in traditional medicine throughout Central and South America for a wide range of conditions. Research on its anticancer properties is ongoing, though clinical evidence in humans is still limited.', imageKeyword: 'graviola soursop herb' },
  { name: 'Pau d\'Arco', category: 'Immune Support', asin: 'B00014GFMO', description: 'Pau d\'Arco is a South American tree bark with powerful antifungal, antibacterial, and immune-modulating properties. It contains lapachol and beta-lapachone, compounds with significant antimicrobial and anti-tumor activity. It is particularly effective for Candida overgrowth and chronic fungal infections that stress and antibiotic use create.', imageKeyword: "pau d'arco herb" },
  { name: 'Suma (Pfaffia)', category: 'Adaptogenic Herbs', asin: 'B00014GFMO', description: 'Suma Root (Pfaffia paniculata) is a South American adaptogen used by indigenous peoples for centuries as a general tonic and energy herb. It contains ecdysteroids, beta-ecdysone, and pfaffic acids that support protein synthesis, hormonal balance, and immune function. It is one of the most complete adaptogens from the Amazon basin.', imageKeyword: 'suma pfaffia herb' },
  { name: 'Copaiba', category: 'Liver & Detox', asin: 'B00014GFMO', description: 'Copaiba is a resin from Amazonian trees with powerful anti-inflammatory properties, primarily through beta-caryophyllene, a cannabinoid that acts on CB2 receptors. Research supports its effectiveness for pain, inflammation, and wound healing. It is used in traditional Amazonian medicine for a wide range of inflammatory conditions.', imageKeyword: 'copaiba resin herb' },
  { name: 'Sangre de Grado (Dragon\'s Blood)', category: 'Digestive Support', asin: 'B00014GFMO', description: 'Sangre de Grado is a red resin from an Amazonian tree used for wound healing, digestive support, and antiviral activity. Research confirms its effectiveness for traveler\'s diarrhea, wound healing, and antiviral properties. It is one of the most remarkable natural wound healers available and has been used by indigenous Amazonian peoples for centuries.', imageKeyword: 'sangre de grado herb' },
  { name: 'Camu Camu', category: 'Immune Support', asin: 'B00014GFMO', description: 'Camu Camu is an Amazonian berry with one of the highest concentrations of Vitamin C of any food - up to 60 times more than oranges. Research supports its antioxidant, anti-inflammatory, and antiviral properties. It is particularly relevant for immune support and the oxidative stress that chronic financial anxiety creates.', imageKeyword: 'camu camu berry' },
  { name: 'Lucuma', category: 'Adaptogenic Herbs', asin: 'B00014GFMO', description: 'Lucuma is a Peruvian fruit used as a natural sweetener and nutritive tonic. It contains beta-carotene, iron, zinc, and B vitamins, and has a naturally sweet, maple-like flavor. It is used in Peruvian traditional medicine as a general tonic and is increasingly popular as a low-glycemic sweetener in health foods.', imageKeyword: 'lucuma fruit powder' },
  { name: 'Mesquite', category: 'Digestive Support', asin: 'B00014GFMO', description: 'Mesquite pod flour is a traditional food of desert-dwelling peoples of North America, with a naturally sweet, caramel-like flavor and a low glycemic index. It is rich in protein, fiber, and minerals, and supports blood sugar regulation. It is a nutritive food-medicine that supports sustained energy without blood sugar spikes.', imageKeyword: 'mesquite pod flour' },
  { name: 'Chaga Dual Extract', category: 'Mushroom Medicine', asin: 'B00FGWQNDC', description: 'Dual-extracted Chaga combines hot water extraction (for polysaccharides) with alcohol extraction (for triterpenes) to provide the full spectrum of Chaga\'s medicinal compounds. This is the most complete and bioavailable form of Chaga. Research supports its antioxidant, immune-modulating, and anti-tumor properties.', imageKeyword: 'chaga dual extract' },
  { name: 'Lion\'s Mane Dual Extract', category: 'Mushroom Medicine', asin: 'B00FGWQNDC', description: 'Dual-extracted Lion\'s Mane provides both the water-soluble beta-glucans and the alcohol-soluble hericenones and erinacines that stimulate nerve growth factor production. This is the most complete and effective form of Lion\'s Mane for cognitive support. Research confirms its effectiveness for improving cognitive function and reducing anxiety.', imageKeyword: "lion's mane dual extract" },
  { name: 'Reishi Dual Extract', category: 'Mushroom Medicine', asin: 'B00FGWQNDC', description: 'Dual-extracted Reishi provides both the water-soluble polysaccharides and the alcohol-soluble triterpenes that give Reishi its medicinal properties. This is the most complete and bioavailable form of Reishi. Research confirms its effectiveness for immune modulation, liver protection, and calming the spirit.', imageKeyword: 'reishi dual extract' },
  { name: 'Cordyceps CS-4', category: 'Mushroom Medicine', asin: 'B00FGWQNDC', description: 'Cordyceps CS-4 is a mycelium-based form of Cordyceps that has been used in Chinese clinical research for decades. It has significant research support for improving oxygen utilization, supporting adrenal function, and enhancing athletic performance. It is the form used in most of the clinical research on Cordyceps.', imageKeyword: 'cordyceps cs-4' },
  { name: 'Maitake D-Fraction', category: 'Mushroom Medicine', asin: 'B00FGWQNDC', description: 'Maitake D-Fraction is a concentrated extract of the beta-glucans from Maitake mushroom, with significant research support for immune modulation and blood sugar regulation. It is the most studied form of Maitake and has been used in Japanese clinical research for cancer support. It is one of the most potent natural immune modulators available.', imageKeyword: 'maitake d-fraction' },
  { name: 'Vitamin C (Liposomal)', category: 'Supplements & Minerals', asin: 'B00014GFMO', description: 'Liposomal Vitamin C encapsulates ascorbic acid in phospholipid liposomes, dramatically increasing absorption compared to standard Vitamin C. Research shows liposomal delivery can achieve blood levels comparable to intravenous Vitamin C. It is the most bioavailable oral form of Vitamin C for immune support, collagen synthesis, and antioxidant protection.', imageKeyword: 'liposomal vitamin c' },
  { name: 'Glutathione (Liposomal)', category: 'Supplements & Minerals', asin: 'B00014GFMO', description: 'Liposomal Glutathione is the most bioavailable oral form of the body\'s master antioxidant. Oral glutathione is poorly absorbed, but liposomal encapsulation dramatically increases cellular delivery. Research supports its effectiveness for detoxification, immune function, and protection against oxidative stress. Chronic stress depletes glutathione significantly.', imageKeyword: 'liposomal glutathione' },
  { name: 'Vitamin K2 (MK-7)', category: 'Supplements & Minerals', asin: 'B00014GFMO', description: 'Vitamin K2 MK-7 is the most bioavailable and long-acting form of K2, with a half-life of 72 hours compared to 1-2 hours for MK-4. It activates osteocalcin (directing calcium to bones) and matrix Gla protein (preventing arterial calcification). It is essential when supplementing with Vitamin D3 and calcium.', imageKeyword: 'vitamin k2 mk7' },
  { name: 'Iodine (Lugol\'s)', category: 'Supplements & Minerals', asin: 'B00014GFMO', description: 'Iodine is essential for thyroid hormone production and is deficient in many people due to soil depletion and avoidance of iodized salt. Thyroid dysfunction is strongly associated with anxiety, depression, fatigue, and weight gain - all common presentations of chronic stress. Lugol\'s solution provides both iodine and iodide for comprehensive thyroid support.', imageKeyword: 'iodine supplement' },
  { name: 'Selenium', category: 'Supplements & Minerals', asin: 'B00014GFMO', description: 'Selenium is an essential mineral that is a cofactor for glutathione peroxidase, the body\'s primary antioxidant enzyme. It is essential for thyroid function, immune health, and protection against oxidative stress. Deficiency is associated with thyroid dysfunction, depression, and immune suppression. Brazil nuts are the richest food source.', imageKeyword: 'selenium supplement' },
  { name: 'Chromium Picolinate', category: 'Supplements & Minerals', asin: 'B00014GFMO', description: 'Chromium is an essential trace mineral that enhances insulin sensitivity and supports blood sugar regulation. Research confirms its effectiveness for reducing carbohydrate cravings, improving blood glucose control, and supporting weight management. It is particularly relevant for the blood sugar dysregulation and carbohydrate cravings that stress creates.', imageKeyword: 'chromium picolinate supplement' },
  { name: 'Lithium Orotate', category: 'Supplements & Minerals', asin: 'B00014GFMO', description: 'Lithium Orotate is a low-dose, nutritional form of lithium that supports mood stability, cognitive function, and neuroprotection. At nutritional doses (5-20mg), it is safe and gentle, unlike pharmaceutical lithium. Research suggests it can reduce depression, anxiety, and aggression, and may have neuroprotective effects against Alzheimer\'s disease.', imageKeyword: 'lithium orotate supplement' },
  { name: 'Taurine', category: 'Supplements & Minerals', asin: 'B00014GFMO', description: 'Taurine is an amino acid with significant roles in cardiovascular health, nervous system function, and antioxidant protection. Research supports its effectiveness for reducing anxiety, improving heart function, and supporting liver health. It is the most abundant amino acid in the heart and is depleted by chronic stress and exercise.', imageKeyword: 'taurine supplement' },
  { name: 'Glycine', category: 'Supplements & Minerals', asin: 'B00014GFMO', description: 'Glycine is a simple amino acid with powerful sleep-supporting and anti-inflammatory properties. Research shows that 3g of glycine before bed significantly improves sleep quality and reduces daytime sleepiness. It also supports collagen synthesis, liver detoxification, and gut health. It has a naturally sweet taste and dissolves easily in water.', imageKeyword: 'glycine supplement' },
];
